package session

import (
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

func TestNewInstance_SoloAgentDefaultsFalse(t *testing.T) {
	inst, err := NewInstance(InstanceOptions{
		Title:   "test",
		Path:    t.TempDir(),
		Program: "claude",
	})
	require.NoError(t, err)
	assert.False(t, inst.SoloAgent, "SoloAgent must default to false")
}

package session

import (
	"testing"
)

func TestNewInstance_SetsPlanFile(t *testing.T) {
	inst, err := NewInstance(InstanceOptions{
		Title:    "plan-worker",
		Path:     ".",
		Program:  "claude",
		TaskFile: "plan-orchestration.md",
	})
	if err != nil {
		t.Fatalf("NewInstance() error = %v", err)
	}
	if inst.TaskFile != "plan-orchestration.md" {
		t.Fatalf("PlanFile = %q, want %q", inst.TaskFile, "plan-orchestration.md")
	}
}

